'use client';

import { useState } from 'react';
import { useAuth } from '@/hooks/use-auth';
import { useRouter } from 'next/navigation';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import { User, Edit, Pencil, UserCheck, Wallet, SlidersHorizontal, MapPin, Footprints, Star, MessageSquare } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import { listings } from '@/lib/mock-data';
import Link from 'next/link';

export default function ProfilePage() {
  const { user, updateUser, surveyData, getMyReviews } = useAuth();
  const router = useRouter();
  const { toast } = useToast();
  
  const [isEditing, setIsEditing] = useState(false);
  const [name, setName] = useState(user?.name || '');
  
  const myReviews = user ? getMyReviews(parseInt(user.id, 10)) : [];

  if (!user) {
    // Or a loading spinner
    return (
      <div className="flex justify-center items-center h-full">
        <p>Loading profile...</p>
      </div>
    );
  }
  
  const handleSave = () => {
    if (updateUser) {
        updateUser({ name });
        toast({ title: "Profile Updated", description: "Your name has been successfully updated." });
        setIsEditing(false);
    } else {
         toast({ variant: "destructive", title: "Update Failed", description: "Could not update profile." });
    }
  };

  return (
    <div className="container mx-auto px-4 md:px-6 py-12">
      <Card className="max-w-2xl mx-auto">
        <CardHeader>
          <div className="flex items-center gap-6">
            <Avatar className="h-24 w-24">
              <AvatarImage src="https://placehold.co/96x96.png" alt={user.name} data-ai-hint="person" />
              <AvatarFallback className="text-3xl">{user.name?.[0]}</AvatarFallback>
            </Avatar>
            <div className="flex-1">
              {isEditing ? (
                 <div className="space-y-2">
                    <Label htmlFor="name">Full Name</Label>
                    <Input 
                      id="name" 
                      value={name} 
                      onChange={(e) => setName(e.target.value)} 
                    />
                  </div>
              ) : (
                <CardTitle className="text-3xl font-headline flex items-center gap-3">
                  {user.name}
                  <Button variant="ghost" size="icon" onClick={() => setIsEditing(true)}>
                      <Pencil className="h-5 w-5" />
                  </Button>
                </CardTitle>
              )}
              <CardDescription className="mt-1">{user.email}</CardDescription>
            </div>
          </div>
          {isEditing && (
              <div className="flex gap-2 pt-4">
                <Button onClick={handleSave}>Save Changes</Button>
                <Button variant="outline" onClick={() => setIsEditing(false)}>Cancel</Button>
              </div>
          )}
        </CardHeader>
        <CardContent className="space-y-6">
          <Separator />
          <div>
            <h3 className="text-xl font-headline mb-4">Your Preferences</h3>
            {surveyData ? (
                 <div className="space-y-4">
                    <div className="flex items-center gap-3">
                      <UserCheck className="h-5 w-5 text-muted-foreground" />
                      <p>You are a <Badge variant="secondary">{surveyData.userType}</Badge></p>
                    </div>
                     <div className="flex items-center gap-3">
                      <Wallet className="h-5 w-5 text-muted-foreground" />
                      <p>Budget: <Badge variant="secondary">₱{surveyData.priceRange[0]} - ₱{surveyData.priceRange[1]}</Badge></p>
                    </div>
                     <div className="flex items-start gap-3">
                      <SlidersHorizontal className="h-5 w-5 text-muted-foreground mt-1" />
                       <div>
                        <p>Amenities:</p>
                        <div className="flex flex-wrap gap-2 mt-2">
                            {surveyData.amenities.map(amenity => <Badge key={amenity} variant="outline">{amenity}</Badge>)}
                        </div>
                      </div>
                    </div>
                     <div className="flex items-center gap-3">
                      <Footprints className="h-5 w-5 text-muted-foreground" />
                      <p>Willing to walk: <Badge variant="secondary">{surveyData.walkingDistance} minutes</Badge></p>
                    </div>
                     <div className="flex items-center gap-3">
                        <MapPin className="h-5 w-5 text-muted-foreground" />
                        <p>Your home base: <span className="font-medium">{surveyData.location || 'Not set'}</span></p>
                    </div>
                    <Button variant="link" onClick={() => router.push('/survey')}>Retake Survey</Button>
                 </div>
            ) : (
                <div className="text-center py-8">
                    <p className="text-muted-foreground">You haven't taken the survey yet.</p>
                    <Button className="mt-4" onClick={() => router.push('/survey')}>Find Recommendations</Button>
                </div>
            )}
          </div>
           <Separator />
           <div>
              <h3 className="text-xl font-headline mb-4">My Reviews</h3>
                {myReviews.length > 0 ? (
                    <div className="space-y-4">
                        {myReviews.map(review => {
                            const listing = listings.find(l => l.id === review.listing_id);
                            return (
                                <Card key={review.review_id} className="p-4">
                                    <div className="flex justify-between items-start">
                                        <div>
                                            <p className="text-sm text-muted-foreground">Review for <Link href={`/listings/${listing?.id}`} className="font-semibold underline hover:text-primary">{listing?.name || 'Unknown Listing'}</Link></p>
                                            <p className="mt-2 text-foreground">{review.comment}</p>
                                        </div>
                                        <div className="flex items-center gap-1">
                                            {[...Array(5)].map((_, i) => (
                                                <Star key={i} className={`h-4 w-4 ${i < review.rating ? 'text-primary fill-primary' : 'text-muted-foreground'}`}/>
                                            ))}
                                        </div>
                                    </div>
                                    <p className="text-xs text-muted-foreground mt-2">{new Date(review.created_at).toLocaleDateString()}</p>
                                </Card>
                            )
                        })}
                    </div>
                ) : (
                    <div className="text-center py-8">
                        <MessageSquare className="mx-auto h-8 w-8 text-muted-foreground" />
                        <p className="mt-2 text-muted-foreground">You haven't written any reviews yet.</p>
                    </div>
                )}
           </div>
        </CardContent>
      </Card>
    </div>
  );
}
